CREATE TABLE "Profile" ("id" TEXT NOT NULL PRIMARY KEY, "userId" TEXT NOT NULL, "photoUrl" TEXT, "businessName" TEXT, "pointPerson" TEXT, "phone" TEXT, "email" TEXT, "website" TEXT, "facebook" TEXT, "instagram" TEXT, "linkedin" TEXT, "title" TEXT, "bio" TEXT, "createdAt" DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP, "updatedAt" DATETIME NOT NULL, CONSTRAINT "Profile_userId_fkey" FOREIGN KEY ("userId") REFERENCES "User" ("id") ON DELETE CASCADE ON UPDATE CASCADE);
